class MemoryManager:
    def __init__(self, total_memory):
        self.total_memory = total_memory
        self.free_blocks = [(0, total_memory)]
        self.allocated = {}

    def allocate(self, process_id, size):
        # Find first fit block
        for i, (start, end) in enumerate(self.free_blocks):
            block_size = end - start
            if block_size >= size:
                # Allocate this block
                self.allocated[process_id] = (start, start + size)
                # Update free blocks
                new_start = start + size
                self.free_blocks.pop(i)
                if block_size > size:
                    self.free_blocks.insert(i, (new_start, end))
                return True
        return False  # No suitable block found

    def deallocate(self, process_id):
        if process_id in self.allocated:
            start, end = self.allocated.pop(process_id)
            self.free_blocks.append((start, end))
            self.free_blocks.sort()  # Sort by address
            return True
        return False

    def status(self):
        return {
            'total': self.total_memory,
            'free': sum(e-s for s,e in self.free_blocks),
            'allocated': len(self.allocated)
        }

# Example usage
mm = MemoryManager(1000)
mm.allocate('P1', 200)
mm.allocate('P2', 300)
mm.deallocate('P1')
print(mm.status())

#include <stdio.h>
#include <stdlib.h>

// Simulating file management service
struct FileControlBlock {
    char filename[50];
    int fileSize;
    char permissions[10];
    int currentPosition;
    char buffer[1024];
};

int createFile(char *filename, char *permissions) {
    struct FileControlBlock *fcb = 
        (struct FileControlBlock *)malloc(sizeof(struct FileControlBlock));

    if (fcb == NULL) {
        return -1; // Error: cannot allocate
    }

    strcpy(fcb->filename, filename);
    strcpy(fcb->permissions, permissions);
    fcb->fileSize = 0;
    fcb->currentPosition = 0;

    // Add to file system directory
    addToDirectory(fcb);

    return 0; // Success
}

int writeFile(struct FileControlBlock *fcb, char *data, int size) {
    if (fcb == NULL || data == NULL) {
        return -1; // Error
    }

    // Check write permission
    if (!hasWritePermission(fcb->permissions)) {
        return -2; // Permission denied
    }

    // Copy data to buffer
    memcpy(fcb->buffer + fcb->currentPosition, data, size);
    fcb->currentPosition += size;
    fcb->fileSize += size;

    return size; // Bytes written
}

int deleteFile(char *filename) {
    struct FileControlBlock *fcb = findInDirectory(filename);

    if (fcb == NULL) {
        return -1; // File not found
    }

    removeFromDirectory(fcb);
    free(fcb);

    return 0; // Success
}

import java.util.LinkedList;
import java.util.Queue;

class DeviceManager {
    private String deviceName;
    private boolean isBusy;
    private Queue<IORequest> requestQueue;
    private byte[] buffer;
    private static final int BUFFER_SIZE = 4096;

    public DeviceManager(String name) {
        this.deviceName = name;
        this.isBusy = false;
        this.requestQueue = new LinkedList<>();
        this.buffer = new byte[BUFFER_SIZE];
    }

    // Submit I/O request to device
    public synchronized int submitRequest(IORequest request) {
        requestQueue.add(request);
        if (!isBusy) {
            processNextRequest();
        }
        return 0; // Request queued
    }

    // Process requests from queue (spooling)
    private void processNextRequest() {
        if (requestQueue.isEmpty()) {
            isBusy = false;
            return;
        }

        isBusy = true;
        IORequest request = requestQueue.poll();

        // Simulate device operation with buffering
        performIO(request);
    }

    private void performIO(IORequest request) {
        // Buffer management: copy data to/from buffer
        if (request.getType() == IORequest.WRITE) {
            // Copy user data to system buffer
            System.arraycopy(request.getData(), 0, buffer, 0, request.getSize());
        }

        // Simulate actual I/O to device
        System.out.println(deviceName + " processing " + request.getType() + " request");

        // After completion, process next request
        processNextRequest();
    }

    public boolean isBusy() {
        return isBusy;
    }
}

class IORequest {
    public static final int READ = 1;
    public static final int WRITE = 2;

    private int type;
    private byte[] data;
    private int size;

    public IORequest(int type, byte[] data, int size) {
        this.type = type;
        this.data = data;
        this.size = size;
    }

    public int getType() { return type; }
    public byte[] getData() { return data; }
    public int getSize() { return size; }
}

// Example usage
public class DeviceManagementDemo {
    public static void main(String[] args) {
        DeviceManager printer = new DeviceManager("Printer");

        // Simulate multiple print jobs (spooling)
        printer.submitRequest(new IORequest(IORequest.WRITE, "Job1".getBytes(), 4));
        printer.submitRequest(new IORequest(IORequest.WRITE, "Job2".getBytes(), 4));
        printer.submitRequest(new IORequest(IORequest.WRITE, "Job3".getBytes(), 4));
    }
}
